        lastFocus = focusLoopEl[focusLoopEl.length - 1];
      } else {
        lastFocus = el.querySelector('[data-tab=menu-tab-9] > button')
      }

      el.removeEventListener('keydown', checkKeyEvent);
      el.addEventListener('keydown', checkKeyEvent);
      return firstFocus;
    }
